/// ### Accounts:
///
///   0. `[writable, signer]` admin
///   1. `[]` registry
///   2. `[writable]` market
///   3. `[]` leader
///   4. `[]` base_mint
///   5. `[]` quote_mint
///   6. `[]` base_token_program
///   7. `[]` quote_token_program
///   8. `[writable]` leader_base_ata
///   9. `[writable]` leader_quote_ata
///   10. `[writable]` market_base_treasury
///   11. `[writable]` market_quote_treasury
///   12. `[]` associated_token_program
///   13. `[]` system_program
///   14. `[]` event_authority
///   15. `[]` program
#[derive(Clone, Debug)]
pub struct ForceWithdrawLeaderCpiBuilder<'a, 'b> {
    instruction: Box<ForceWithdrawLeaderCpiBuilderInstruction<'a, 'b>>,
}

impl<'a, 'b> ForceWithdrawLeaderCpiBuilder<'a, 'b> {
    pub fn new(program: &'b solana_account_info::AccountInfo<'a>) -> Self {
        let instruction = Box::new(ForceWithdrawLeaderCpiBuilderInstruction {
            __program: program,
            admin: None,
            registry: None,
            market: None,
            leader: None,
            base_mint: None,
            quote_mint: None,
            base_token_program: None,
            quote_token_program: None,
            leader_base_ata: None,
            leader_quote_ata: None,
            market_base_treasury: None,
            market_quote_treasury: None,
            associated_token_program: None,
            system_program: None,
            event_authority: None,
            program: None,
            vault_idx: None,
            __remaining_accounts: Vec::new(),
        });
        Self { instruction }
    }
    /// Registry admin. Funds the leader payout ATAs when `init_if_needed`
    /// has to allocate them.
    #[inline(always)]
    pub fn admin(&mut self, admin: &'b solana_account_info::AccountInfo<'a>) -> &mut Self {
        self.instruction.admin = Some(admin);
        self
    }
    /// Singleton registry, read for the admin-membership check.
    #[inline(always)]
    pub fn registry(&mut self, registry: &'b solana_account_info::AccountInfo<'a>) -> &mut Self {
        self.instruction.registry = Some(registry);
        self
    }
    /// Market the vault lives on.
    #[inline(always)]
    pub fn market(&mut self, market: &'b solana_account_info::AccountInfo<'a>) -> &mut Self {
        self.instruction.market = Some(market);
        self
    }
    /// The vault's leader — the payout target. Not a signer. Verified
    /// in-handler against `vault.leader`.
    /// CHECK: matched against `vault.leader` in the handler and bound as
    /// the `associated_token::authority` of the payout ATAs below.
    #[inline(always)]
    pub fn leader(&mut self, leader: &'b solana_account_info::AccountInfo<'a>) -> &mut Self {
        self.instruction.leader = Some(leader);
        self
    }
    #[inline(always)]
    pub fn base_mint(&mut self, base_mint: &'b solana_account_info::AccountInfo<'a>) -> &mut Self {
        self.instruction.base_mint = Some(base_mint);
        self
    }
    #[inline(always)]
    pub fn quote_mint(
        &mut self,
        quote_mint: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.quote_mint = Some(quote_mint);
        self
    }
    #[inline(always)]
    pub fn base_token_program(
        &mut self,
        base_token_program: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.base_token_program = Some(base_token_program);
        self
    }
    #[inline(always)]
    pub fn quote_token_program(
        &mut self,
        quote_token_program: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.quote_token_program = Some(quote_token_program);
        self
    }
    /// Leader's base payout ATA — created (admin-funded) if absent.
    #[inline(always)]
    pub fn leader_base_ata(
        &mut self,
        leader_base_ata: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.leader_base_ata = Some(leader_base_ata);
        self
    }
    /// Leader's quote payout ATA — created (admin-funded) if absent.
    #[inline(always)]
    pub fn leader_quote_ata(
        &mut self,
        leader_quote_ata: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.leader_quote_ata = Some(leader_quote_ata);
        self
    }
    #[inline(always)]
    pub fn market_base_treasury(
        &mut self,
        market_base_treasury: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.market_base_treasury = Some(market_base_treasury);
        self
    }
    #[inline(always)]
    pub fn market_quote_treasury(
        &mut self,
        market_quote_treasury: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.market_quote_treasury = Some(market_quote_treasury);
        self
    }
    #[inline(always)]
    pub fn associated_token_program(
        &mut self,
        associated_token_program: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.associated_token_program = Some(associated_token_program);
        self
    }
    #[inline(always)]
    pub fn system_program(
        &mut self,
        system_program: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.system_program = Some(system_program);
        self
    }
    /// CHECK: Only the event authority can invoke self-CPI
    #[inline(always)]
    pub fn event_authority(
        &mut self,
        event_authority: &'b solana_account_info::AccountInfo<'a>,
    ) -> &mut Self {
        self.instruction.event_authority = Some(event_authority);
        self
    }
    /// CHECK: Kept for v1-compatible account ordering and IDL shape
    #[inline(always)]
    pub fn program(&mut self, program: &'b solana_account_info::AccountInfo<'a>) -> &mut Self {
        self.instruction.program = Some(program);
        self
    }
    #[inline(always)]
    pub fn vault_idx(&mut self, vault_idx: u32) -> &mut Self {
        self.instruction.vault_idx = Some(vault_idx);
        self
    }
    /// Add an additional account to the instruction.
    #[inline(always)]
    pub fn add_remaining_account(
        &mut self,
        account: &'b solana_account_info::AccountInfo<'a>,
        is_writable: bool,
        is_signer: bool,
    ) -> &mut Self {
        self.instruction
            .__remaining_accounts
            .push((account, is_writable, is_signer));
        self
    }
    /// Add additional accounts to the instruction.
    ///
    /// Each account is represented by a tuple of the `AccountInfo`, a `bool` indicating whether the account is writable or not,
    /// and a `bool` indicating whether the account is a signer or not.
    #[inline(always)]
    pub fn add_remaining_accounts(
        &mut self,
        accounts: &[(&'b solana_account_info::AccountInfo<'a>, bool, bool)],
    ) -> &mut Self {
        self.instruction
            .__remaining_accounts
            .extend_from_slice(accounts);
        self
    }
    #[inline(always)]
    pub fn invoke(&self) -> solana_program_error::ProgramResult {
        self.invoke_signed(&[])
    }
    #[allow(clippy::clone_on_copy)]
    #[allow(clippy::vec_init_then_push)]
    pub fn invoke_signed(&self, signers_seeds: &[&[&[u8]]]) -> solana_program_error::ProgramResult {
        let args = ForceWithdrawLeaderInstructionArgs {
            vault_idx: self
                .instruction
                .vault_idx
                .clone()
                .expect("vault_idx is not set"),
        };
        let instruction = ForceWithdrawLeaderCpi {
            __program: self.instruction.__program,

            admin: self.instruction.admin.expect("admin is not set"),

            registry: self.instruction.registry.expect("registry is not set"),

            market: self.instruction.market.expect("market is not set"),

            leader: self.instruction.leader.expect("leader is not set"),

            base_mint: self.instruction.base_mint.expect("base_mint is not set"),

            quote_mint: self.instruction.quote_mint.expect("quote_mint is not set"),

            base_token_program: self
                .instruction
                .base_token_program
                .expect("base_token_program is not set"),

            quote_token_program: self
                .instruction
                .quote_token_program
                .expect("quote_token_program is not set"),

            leader_base_ata: self
                .instruction
                .leader_base_ata
                .expect("leader_base_ata is not set"),

            leader_quote_ata: self
                .instruction
                .leader_quote_ata
                .expect("leader_quote_ata is not set"),

            market_base_treasury: self
                .instruction
                .market_base_treasury
                .expect("market_base_treasury is not set"),

            market_quote_treasury: self
                .instruction
                .market_quote_treasury
                .expect("market_quote_treasury is not set"),

            associated_token_program: self
                .instruction
                .associated_token_program
                .expect("associated_token_program is not set"),

            system_program: self
                .instruction
                .system_program
                .expect("system_program is not set"),

            event_authority: self
                .instruction
                .event_authority
                .expect("event_authority is not set"),

            program: self.instruction.program.expect("program is not set"),
            __args: args,
        };
        instruction.invoke_signed_with_remaining_accounts(
            signers_seeds,
            &self.instruction.__remaining_accounts,
        )
    }
}

#[derive(Clone, Debug)]
struct ForceWithdrawLeaderCpiBuilderInstruction<'a, 'b> {
    __program: &'b solana_account_info::AccountInfo<'a>,
    admin: Option<&'b solana_account_info::AccountInfo<'a>>,
    registry: Option<&'b solana_account_info::AccountInfo<'a>>,
    market: Option<&'b solana_account_info::AccountInfo<'a>>,
    leader: Option<&'b solana_account_info::AccountInfo<'a>>,
    base_mint: Option<&'b solana_account_info::AccountInfo<'a>>,
    quote_mint: Option<&'b solana_account_info::AccountInfo<'a>>,
    base_token_program: Option<&'b solana_account_info::AccountInfo<'a>>,
    quote_token_program: Option<&'b solana_account_info::AccountInfo<'a>>,
    leader_base_ata: Option<&'b solana_account_info::AccountInfo<'a>>,
    leader_quote_ata: Option<&'b solana_account_info::AccountInfo<'a>>,
    market_base_treasury: Option<&'b solana_account_info::AccountInfo<'a>>,
    market_quote_treasury: Option<&'b solana_account_info::AccountInfo<'a>>,
    associated_token_program: Option<&'b solana_account_info::AccountInfo<'a>>,
    system_program: Option<&'b solana_account_info::AccountInfo<'a>>,
    event_authority: Option<&'b solana_account_info::AccountInfo<'a>>,
    program: Option<&'b solana_account_info::AccountInfo<'a>>,
    vault_idx: Option<u32>,
    /// Additional instruction accounts `(AccountInfo, is_writable, is_signer)`.
    __remaining_accounts: Vec<(&'b solana_account_info::AccountInfo<'a>, bool, bool)>,
}
